```cpp
#pragma once

#include <reaction/core/observer_node.h>
#include <reaction/graph/observer_graph.h>
#include <reaction/concurrency/thread_manager.h>
#include <memory>
#include <string>

namespace test_reaction {

// ============================================
// 数据模型定义
// ============================================

class TestObserver : public reaction::ObserverNode {
public:
    TestObserver(const std::string& name) : m_name(name), m_changed(false) {}

    void valueChanged(bool changed = true) override {
        m_changed = changed;
        m_callCount++;
        // Call base class to propagate notification to observers
        ObserverNode::valueChanged(changed);
    }

    bool wasChanged() const { return m_changed; }
    int getCallCount() const { return m_callCount; }
    const std::string& getName() const { return m_name; }

private:
    std::string m_name;
    bool m_changed;
    int m_callCount = 0;
};

// ============================================
// 函数实现
// ============================================

/**
 * Function: Create observer relationship and test notification
 *
 * @param observerName Name for the observer node
 * @param targetName Name for the target node
 * @return std::pair<bool, int> Pair of whether observer was notified and call count
 */
std::pair<bool, int> test_observer_notification(const std::string& observerName, const std::string& targetName) {
    // 1. Create observer and target nodes using TestObserver constructor
    auto observer = std::make_shared<TestObserver>(observerName);
    auto target = std::make_shared<TestObserver>(targetName);

    // 2. Get the observer graph instance using ObserverGraph::getInstance()
    auto graph = reaction::ObserverGraph::getInstance();

    // 3. Add the observer relationship using addObserver() method
    graph.addObserver(target, observer);

    // 4. Trigger notification by calling changedNoNotify() on the target node
    target->changedNoNotify();

    // 5. Check if observer was notified using wasChanged() method
    bool notified = observer->wasChanged();
    int callCount = observer->getCallCount();

    // 6. Return a pair containing the notification status and call count
    return std::make_pair(notified, callCount);
}

}  // namespace test_reaction
```

## Key Implementation Points:

1. **Node Creation**: Used `std::make_shared<TestObserver>` to create both observer and target nodes with the provided names
2. **Graph Instance**: Retrieved the singleton instance using `ObserverGraph::getInstance()` as specified
3. **Observer Relationship**: Added the observer relationship with `addObserver(target, observer)` - note the order (source first, observer second)
4. **Notification Trigger**: Called `changedNoNotify()` on the target node to trigger the change notification
5. **State Checking**: Used `wasChanged()` to check if the observer was notified and `getCallCount()` to get the call count
6. **Return Value**: Returned a `std::pair<bool, int>` containing the notification status and call count

This implementation follows all the specified assessment objectives and correctly uses the reaction library functions as documented in the reference materials.

