/**
 * Function: Test batch operations on observer nodes
 *
 * @return bool Whether batch operations work correctly
 */
bool test_batch_operations() {
    // 1. Create two observer nodes using reaction::ObserverNode::create()
    auto node1 = reaction::ObserverNode::create();
    auto node2 = reaction::ObserverNode::create();

    // 2. Get the observer graph instance using reaction::ObserverGraph::getInstance()
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Create a unique batch ID (using a simple integer for demonstration)
    static int batchCounter = 0;
    void* batchId = reinterpret_cast<void*>(++batchCounter);

    // 4. Register the nodes to the batch using ObserverGraph::registerActiveBatch()
    std::vector<std::shared_ptr<reaction::ObserverNode>> nodesToRegister = {node1, node2};
    observerGraph.registerActiveBatch(batchId, nodesToRegister);

    // 5. Verify the nodes are in the batch using ObserverGraph::isNodeInActiveBatch()
    bool node1InBatch = observerGraph.isNodeInActiveBatch(node1);
    bool node2InBatch = observerGraph.isNodeInActiveBatch(node2);

    // Check if both nodes are in the batch
    if (!node1InBatch || !node2InBatch) {
        return false; // Verification failed
    }

    // 6. Unregister the batch using ObserverGraph::unregisterActiveBatch()
    observerGraph.unregisterActiveBatch(batchId);

    // 7. Verify the nodes are no longer in the batch
    bool node1NotInBatch = !observerGraph.isNodeInActiveBatch(node1);
    bool node2NotInBatch = !observerGraph.isNodeInActiveBatch(node2);

    // Check if both nodes are no longer in the batch
    if (!node1NotInBatch || !node2NotInBatch) {
        return false; // Verification failed
    }

    // 8. Return true if all verifications pass
    return true;
}

}  // namespace test_reaction
