#include <reaction/reaction.h>

namespace test_reaction {

struct AlwaysTriggerResult {
    int recomputeCountAfterInit;
    int recomputeCountAfterDuplicateWrite;
};

AlwaysTriggerResult test_always_trigger(int initialValue) {
    // 1. Create a reactive variable using reaction::var with the initial value
    auto reactiveVar = reaction::var(initialValue);

    // 2. Create a counter variable to track recomputation count
    int recomputeCounter = 0;

    // 3. Create an AlwaysTrig calculation using reaction::calc that doubles the value and increments counter
    auto alwaysTrigCalc = reaction::calc<reaction::AlwaysTrig>([&]() {
        // Double the value from the reactive variable
        int doubledValue = reactiveVar() * 2;
        // Increment the counter each time this calculation runs
        recomputeCounter++;
        return doubledValue;
    });

    // 4. Store the initial recompute count after calculation creation
    int countAfterInit = recomputeCounter;

    // 5. Write the same value back to the reactive variable to trigger duplicate write
    reactiveVar.value(initialValue);

    // 6. Store the recompute count after the duplicate write
    int countAfterDuplicateWrite = recomputeCounter;

    // 7. Force evaluation of the calculation to avoid unused variable warnings
    (void)alwaysTrigCalc();

    // 8. Return the result with both recompute counts
    return {countAfterInit, countAfterDuplicateWrite};
}

}  // namespace test_reaction
```

